    private void ExtractSettings(XmlNode node, string prefix, Dictionary<string, string> settings)
    {
        if (node == null) return;
        
        string currentPath = string.IsNullOrEmpty(prefix) ? node.Name : $"{prefix}.{node.Name}";
        
        if (node.Attributes != null && node.Attributes.Count > 0)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string key = $"{currentPath}.{attr.Name}";
                settings[key] = attr.Value;
            }
        }
        
        if (node.HasChildNodes)
        {
            bool hasElementChildren = false;
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    hasElementChildren = true;
                    break;
                }
            }
            
            if (!hasElementChildren && node.InnerText != null && !string.IsNullOrWhiteSpace(node.InnerText))
            {
                settings[currentPath] = node.InnerText.Trim();
            }
            else
            {
                foreach (XmlNode child in node.ChildNodes)
                {
                    if (child.NodeType == XmlNodeType.Element)
                    {
                        ExtractSettings(child, currentPath, settings);
                    }
                }
            }
        }
    }

